{"title":"PrimaryProcessingDurationMs by action with a max line","type":"vega","aggs":[],"params":{"spec":"{
    "$schema": "https://vega.github.io/schema/vega-lite/v5.json",
    "title": "sum primaryProcessingDurationMs by action",
    "data": {
      "url": {
        "%context%": true,
        "%timefield%": "@timestamp",
        "index": "airtable-applogs-*",
        "body": {
          "aggs": {
            "filtered": {
              "filter": {
                "match_phrase": {
                  "msg": "crud request log line"
                }
              },
              "aggs": {
                "time_buckets": {
                  "date_histogram": {
                    "field": "@timestamp",
                    "interval": {
                      "%autointerval%": true
                    },
                    "extended_bounds": {
                      "min": {
                        "%timefilter%": "min"
                      },
                      "max": {
                        "%timefilter%": "max"
                      }
                    },
                    "min_doc_count": 0
                  },
                  "aggs": {
                    "actions": {
                      "terms": {
                        "field": "action",
                        "size": 50
                      },
                      "aggs": {
                        "total_duration": {
                          "sum": {
                            "field": "primaryProcessingDurationMs"
                          }
                        }
                      }
                    }
                  }
                }
              }
            }
          },
          "size": 0
        }
      },
      "format": {
        "property": "aggregations.filtered.time_buckets.buckets"
      }
    },
    "transform": [
      {
        "calculate": "datum.actions.buckets",
        "as": "action_list"
      },
      {
        "flatten": ["action_list"]
      },
      {
        "calculate": "datum.action_list.key",
        "as": "raw_action"
      },
      {
        "calculate": "datum.action_list.total_duration.value",
        "as": "duration"
      },
      {
        "joinaggregate": [
          {
            "op": "sum",
            "field": "duration",
            "as": "action_global_total"
          }
        ],
        "groupby": ["raw_action"]
      },
      {
        "window": [
          {
            "op": "dense_rank",
            "as": "action_rank"
          }
        ],
        "sort": [
          {
            "field": "action_global_total",
            "order": "descending"
          }
        ]
      },
      {
        "calculate": "datum.action_rank <= 25 ? datum.raw_action : 'Other'",
        "as": "action"
      }
    ],
    "layer": [
      {
        "mark": {
          "type": "bar"
        },
        "encoding": {
          "x": {
            "field": "key",
            "type": "temporal",
            "axis": {
              "title": "@timestamp"
            }
          },
          "y": {
            "aggregate": "sum",
            "field": "duration",
            "type": "quantitative",
            "stack": true,
            "axis": {
              "title": "Sum of primaryProcessingDurationMs"
            }
          },
          "color": {
            "field": "action",
            "type": "nominal",
            "scale": {
              "range": [
                "#4e79a7",
                "#f28e2b",
                "#e15759",
                "#76b7b2",
                "#59a14f",
                "#edc948",
                "#b07aa1",
                "#ff9da7",
                "#9c755f",
                "#1b9e77",
                "#d95f02",
                "#7570b3",
                "#e7298a",
                "#66a61e",
                "#e6ab02",
                "#a6761d",
                "#8dd3c7",
                "#fb8072",
                "#80b1d3",
                "#fdb462",
                "#b3de69",
                "#bc80bd",
                "#fccde5",
                "#d9d9d9",
                "#405de6",
                "#bab0ac"
              ]
            },
            "legend": {
              "title": "action"
            }
          },
          "order": {
            "field": "action_global_total",
            "type": "quantitative",
            "sort": "descending"
          },
          "tooltip": [
            {
              "field": "action",
              "type": "nominal",
              "title": "Action"
            },
            {
              "aggregate": "sum",
              "field": "duration",
              "type": "quantitative",
              "title": "Duration (ms)",
              "format": ",.0f"
            },
            {
              "field": "key",
              "type": "temporal",
              "title": "Time"
            }
          ]
        }
      },
      {
        "transform": [
          {
            "aggregate": [
              {
                "op": "min",
                "field": "key",
                "as": "min_key"
              },
              {
                "op": "max",
                "field": "key",
                "as": "max_key"
              },
              {
                "op": "distinct",
                "field": "key",
                "as": "num_buckets"
              }
            ]
          },
          {
            "calculate": "(datum.max_key - datum.min_key) / max(datum.num_buckets - 1, 1)",
            "as": "threshold"
          }
        ],
        "mark": {
          "type": "rule",
          "color": "red",
          "strokeDash": [8, 4],
          "strokeWidth": 2
        },
        "encoding": {
          "y": {
            "field": "threshold",
            "type": "quantitative"
          }
        }
      }
    ]
  }"}}
